// 1. ChangeNotifier model
class CartNotifier extends ChangeNotifier {
  final List<Product> _items = [];
  List<Product> get items => List.unmodifiable(_items);
  int get count => _items.length;
  double get total => _items.fold(0, (s, p) => s + p.price);

  void add(Product p) { _items.add(p); notifyListeners(); }
  void remove(Product p) { _items.remove(p); notifyListeners(); }
}

// 2. Provide at root
void main() {
  runApp(
    MultiProvider(
      providers: [
        ChangeNotifierProvider(create: (_) => CartNotifier()),
        ChangeNotifierProvider(create: (_) => AuthNotifier()),
      ],
      child: const MyApp(),
    ),
  );
}

// 3a. context.watch — full widget rebuild
class CartBadge extends StatelessWidget {
  const CartBadge({super.key});
  @override Widget build(BuildContext context) {
    final count = context.watch<CartNotifier>().count; // subscribes
    return Badge(label: Text('$count'), child: const Icon(Icons.cart));
  }
}

// 3b. Consumer — only subtree rebuilds
Consumer<CartNotifier>(
  builder: (context, cart, child) => Badge(
    label: Text('${cart.count}'),
    child: child!, // static child won't rebuild
  ),
  child: const Icon(Icons.shopping_cart),
)

// 3c. context.read — no subscription (callbacks only!)
ElevatedButton(
  onPressed: () => context.read<CartNotifier>().add(product),
  child: const Text('Add to Cart'),
)

// 3d. context.select — granular subscription
final count = context.select<CartNotifier, int>((c) => c.count);
// Only rebuilds when count changes, not when prices change

// Setup: ApiService depends on AuthToken
class AuthToken extends ChangeNotifier {
  String? _token;
  String? get token => _token;

  Future<void> login(String email, String pass) async {
    _token = await AuthApi.login(email, pass);
    notifyListeners();
  }
}

class ApiService {
  final String? authToken;
  ApiService({this.authToken});

  Future<List<Product>> getProducts() async {
    // Uses auth token in headers
    final dio = Dio();
    if (authToken != null) dio.options.headers['Authorization'] = 'Bearer $authToken';
    final response = await dio.get('/products');
    return (response.data as List).map((e) => Product.fromJson(e)).toList();
  }
}

// ── ProxyProvider — rebuild ApiService when token changes ──
MultiProvider(
  providers: [
    ChangeNotifierProvider(create: (_) => AuthToken()),

    // ProxyProvider: ApiService is rebuilt whenever AuthToken changes
    ProxyProvider<AuthToken, ApiService>(
      update: (context, auth, previousService) => ApiService(
        authToken: auth.token,
      ),
    ),

    // ChangeNotifierProxyProvider: the notifier itself needs a dependency
    ChangeNotifierProxyProvider<AuthToken, CartNotifier>(
      create: (_) => CartNotifier(null),
      update: (context, auth, previous) {
        return previous!..updateToken(auth.token);
      },
    ),
  ],
  child: const MyApp(),
)

// In widget — just read ApiService normally
final api = context.read<ApiService>();
final products = await api.getProducts();

// ── Provider — runtime safety hole ──
// Setup
MultiProvider(
  providers: [
    ChangeNotifierProvider(create: (_) => AuthNotifier()),
  ],
  child: const App(),
);

// Somewhere deep, in a screen that accidentally got rendered without the provider above:
final auth = Provider.of<AuthNotifier>(context); // ❌ ProviderNotFoundException at runtime

// ── Riverpod — compile-time safety ──
// Setup
ProviderScope(
  child: const App(),
);
final authProvider = ChangeNotifierProvider<AuthNotifier>((ref) => AuthNotifier());

// Anywhere
final auth = ref.watch(authProvider); // ✅ Type-checked; works without context

// ── Migration path: Provider → Riverpod ──
// 1. Wrap the app in ProviderScope at the same level as MultiProvider
// 2. Move services to Riverpod Providers one at a time, leaving the old MultiProvider in place for now
// 3. Replace context.watch/read with ref.watch/read in widgets that switched
// 4. When all consumers of a service are migrated, remove it from MultiProvider
// 5. Eventually drop MultiProvider entirely
//
// You can run both side-by-side during the transition. Riverpod wraps Flutter widgets;
// Provider wraps InheritedWidget; they don't conflict.

// ── MultiProvider — clean structure ──
void main() {
  runApp(
    MultiProvider(
      providers: [
        // Singletons available everywhere — eager so init errors surface immediately
        Provider<Logger>(
          create: (_) => Logger(),
          dispose: (_, logger) => logger.flush(),
          lazy: false,
        ),
        Provider<Dio>(
          create: (_) => createDio(),
          dispose: (_, dio) => dio.close(force: true),
        ),

        // Services that depend on the ones above
        ProxyProvider<Dio, AuthRepository>(
          update: (_, dio, __) => AuthRepository(dio),
        ),

        // ChangeNotifier — auto-disposed
        ChangeNotifierProvider<AuthNotifier>(
          create: (ctx) => AuthNotifier(ctx.read<AuthRepository>())..bootstrap(),
        ),
      ],
      child: const MyApp(),
    ),
  );
}

// ── lazy: true — created on first read ──
Provider<HeavyAnalyticsClient>(
  create: (_) => HeavyAnalyticsClient.start(),  // expensive
  lazy: true,                                    // skip if no consumer ever reads it
);

// ── Manual dispose for plain Provider ──
Provider<WebSocketChannel>(
  create: (_) => WebSocketChannel.connect(Uri.parse('wss://...')),
  dispose: (_, ch) => ch.sink.close(),           // ✅ critical
);

// ── ChangeNotifier with internal subscription — clean it up yourself ──
class FeedNotifier extends ChangeNotifier {
  FeedNotifier(this._repo) {
    _sub = _repo.changes().listen((_) => notifyListeners());
  }
  final FeedRepository _repo;
  late final StreamSubscription _sub;

  @override
  void dispose() {
    _sub.cancel();                               // ✅ otherwise leaks
    super.dispose();
  }
}

// ── ❌ Anti-pattern — initialization in build() ──
class App extends StatelessWidget {
  @override Widget build(BuildContext context) {
    return ChangeNotifierProvider(
      create: (_) => AuthNotifier()..bootstrap(),  // ✅ create runs once
      child: ChangeNotifierProvider(
        create: (ctx) {
          // ❌ Reading another provider via Provider.of(context) here without listen: false
          //    causes rebuilds; do `ctx.read<...>()` instead, which doesn't subscribe.
          final auth = ctx.read<AuthNotifier>();
          return ProfileNotifier(auth);
        },
        child: const Home(),
      ),
    );
  }
}

