// ── Refresh trick for FutureProvider ──
// Wrap in a key so changing the key remounts the provider
class Profile extends StatefulWidget { ... }
class _ProfileState extends State<Profile> {
  int _ver = 0;
  Future<void> _refresh() async => setState(() => _ver++);

  @override Widget build(BuildContext context) {
    return FutureProvider<User>.value(
      key: ValueKey(_ver),                        // ✅ remount → re-run create
      initialData: User.empty(),
      value: api.user('me'),
      child: ProfileBody(onRefresh: _refresh),
    );
  }
}

// ── ❌ Anti-pattern — using FutureProvider for tri-state UI ──
// FutureProvider exposes `T`. You can't tell apart "loading", "error", and "empty data".
// For UIs that need to render those three differently, use a Notifier with a sealed state
// (or migrate that piece to Riverpod's AsyncNotifier).

// ── 1) Notifier under test ──
class CartNotifier extends ChangeNotifier {
  CartNotifier(this._api);
  final CartApi _api;
  List<Item> _items = [];
  List<Item> get items => List.unmodifiable(_items);
  bool _loading = false;
  bool get isLoading => _loading;

  Future<void> load() async {
    _loading = true; notifyListeners();
    _items = await _api.fetch();
    _loading = false; notifyListeners();
  }
  void add(Item i) { _items = [..._items, i]; notifyListeners(); }
}

// ── 2) Unit test — no widgets ──
import 'package:mocktail/mocktail.dart';
class MockCartApi extends Mock implements CartApi {}

void main() {
  test('CartNotifier loads items', () async {
    final api = MockCartApi();
    when(() => api.fetch()).thenAnswer((_) async => [Item('a'), Item('b')]);

    final cart = CartNotifier(api);
    expect(cart.items, isEmpty);
    await cart.load();
    expect(cart.items, hasLength(2));
    verify(() => api.fetch()).called(1);
  });
}

