import 'package:provider/provider.dart';

class FakeCart extends ChangeNotifier implements CartNotifier {
  @override List<Item> get items => [Item('test')];
  @override bool get isLoading => false;
  @override Future<void> load() async {}
  @override void add(Item i) {}
  // ... pass-through stubs for other members
  @override CartApi get _api => throw UnimplementedError();
}

testWidgets('shows cart count', (tester) async {
  await tester.pumpWidget(
    ChangeNotifierProvider<CartNotifier>.value(
      value: FakeCart(),
      child: const MaterialApp(home: CartBadge()),
    ),
  );
  await tester.pumpAndSettle();
  expect(find.text('1'), findsOneWidget);
});

