// ── ListenableProvider with a ValueNotifier ──
final _theme = ValueNotifier<ThemeMode>(ThemeMode.system);

MaterialApp(
  theme: ThemeData.light(),
  darkTheme: ThemeData.dark(),
  builder: (context, child) {
    return ListenableProvider<ValueNotifier<ThemeMode>>.value(
      value: _theme,                    // ✅ no auto-dispose; we own the lifetime
      child: child!,
    );
  },
  themeMode: _theme.value,
);

// Consumer reads the current value via context.watch
class ThemeAwareIcon extends StatelessWidget {
  const ThemeAwareIcon({super.key});
  @override Widget build(BuildContext context) {
    final notifier = context.watch<ValueNotifier<ThemeMode>>();
    return Icon(notifier.value == ThemeMode.dark ? Icons.dark_mode : Icons.light_mode);
  }
}

// ── Merging listenables ──
class _Composite extends StatelessWidget {
  const _Composite({required this.a, required this.b, required this.child});
  final Listenable a;
  final Listenable b;
  final Widget child;
  @override Widget build(BuildContext context) {
    return ListenableProvider<Listenable>.value(
      value: Listenable.merge([a, b]),  // rebuild on either
      child: child,
    );
  }
}

