// ── Coarse state — User has many fields ──
class UserNotifier extends ChangeNotifier {
  String _name = 'Ada';
  int _age = 30;
  String _email = 'a@x.com';
  String get name => _name;
  int get age => _age;
  String get email => _email;
  void setName(String v)  { _name = v;  notifyListeners(); }
  void setAge(int v)      { _age = v;   notifyListeners(); }
  void setEmail(String v) { _email = v; notifyListeners(); }
}

// ❌ Watches whole notifier — rebuilds on age, email, ANY change
class NameLabelBad extends StatelessWidget {
  const NameLabelBad({super.key});
  @override Widget build(BuildContext context) {
    final user = context.watch<UserNotifier>();
    return Text(user.name);
  }
}

// ✅ context.select — rebuilds only when name changes
class NameLabel extends StatelessWidget {
  const NameLabel({super.key});
  @override Widget build(BuildContext context) {
    final name = context.select<UserNotifier, String>((u) => u.name);
    return Text(name);
  }
}

// ✅ Selector — same logic, with child optimization
Selector<UserNotifier, String>(
  selector: (_, u) => u.name,
  builder: (_, name, child) {
    return Row(children: [
      Text(name),
      child!,                     // expensive trailing widget never rebuilds
    ]);
  },
  child: const ExpensiveTrailing(),
);

// ── Selecting a tuple ──
final nameAndAge = context.select<UserNotifier, (String, int)>(
  (u) => (u.name, u.age),
);
// Records have value equality — rebuilds only when name OR age changes

// ── ❌ Selecting a List by reference rebuilds every time ──
final items = context.select<CartNotifier, List<Item>>((c) => c.items);
// If CartNotifier returns a new list (e.g. List.unmodifiable(_items)) on every read,
// the selector sees a different reference each call → constant rebuilds.
//
// ✅ Either return the length, or override == on the list (use IList from
// fast_immutable_collections), or split into focused selectors:
final count = context.select<CartNotifier, int>((c) => c.items.length);

