// Riverpod — ProviderContainer or Ref work without BuildContext
class SyncService {
  final Ref ref;
  SyncService(this.ref);
  void start() {
    final api = ref.read(apiClientProvider);   // ✅ works anywhere
  }
}

// ── 3) AsyncValue — first-class async state ──
final profileProvider = FutureProvider<User>((ref) async => api.me());

// Consumer
ref.watch(profileProvider).when(
  data:    (user) => Text(user.name),
  loading: ()      => const _Spinner(),
  error:   (e, _)  => _Error(error: e),
);
// Provider's FutureProvider doesn't give you this — you'd have to build the three states yourself.

// ── 4) Family — parameterized providers ──
final productProvider = FutureProvider.family<Product, int>(
  (ref, id) => ref.watch(apiProvider).product(id),
);
ref.watch(productProvider(42));                // each id cached separately

// Provider equivalent requires building your own keyed cache by hand.

// ── 5) Testing — pure Dart, no widget tree ──
test('login', () async {
  final container = ProviderContainer(overrides: [
    apiClientProvider.overrideWithValue(FakeApiClient()),
  ]);
  addTearDown(container.dispose);

  await container.read(authProvider.notifier).signIn('a@x.com', 'pwd');
  expect(container.read(authProvider).value?.email, 'a@x.com');
});

// ── Summary in one line ──
// Provider gives you DI through the widget tree.
// Riverpod gives you DI as a typed, reactive graph that happens to render UI.
